class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> result;
        backtrack(num, result, 0);
        return result;
    }

    bool backtrack(string& num, vector<int>& result, int start) {
        if (num.empty()) return result.size() >= 3;
        if (start < result.size() - 1 && result[start] + result[start + 1] > INT_MAX) return false;
        for (int len = 1; len <= 18 && start + len <= result.size(); ++len) {
            string prefix = num.substr(0, len);
            if (prefix[0] == '0' && len > 1) break;
            long long val = stoll(prefix);
            if (val > INT_MAX) break;
            if (val == INT_MAX) {
                if (start + len == result.size()) return false;
                continue;
            }
            if (start + len == result.size()) {
                result.push_back(val);
                return backtrack(num.substr(len), result, result.size() - 1);
            }
            if (val == result[start] + result[start + 1]) {
                result.push_back(val);
                if (backtrack(num.substr(len), result, result.size() - 1)) return true;
                result.pop_back();
            }
        }
        return false;
    }
};
```

efficiency: HIGH
time complexity: O(2^n * m) where n is the number of digits in the input string and m is the maximum length of a Fibonacci number
space complexity: O(n + m)
